        constructor(str) {
            this.str = str;
            this.memo = {};
        }
        processCharacter(char, index) {
            if (this.memo.hasOwnProperty(index)) {
                return this.memo[index];
            }
            const transformed = index % 2 === 0 ? char.toUpperCase() : char.toLowerCase();
            this.memo[index] = transformed;
            return transformed;
        }
        recursiveBuild(index, acc) {
            if (index >= this.str.length) {
                return acc;
            }
            const char = this.processCharacter(this.str[index], index);
            return this.recursiveBuild(index + 1, acc + char);
        }
        buildString() {
            return this.recursiveBuild(0, '');
        }
    }
    const transformer = new StringTransformer(a);
    return transformer.buildString();
}
module.exports = { stuff };
